/**
 * validation.js — Input validation helpers for API endpoints.
 *
 * Each validator returns { valid: boolean, errors: string[] }.
 * Route handlers call a single top-level validator per endpoint and return
 * 400 with the errors array when valid is false.
 */

'use strict';

// RFC 5322-inspired email regex — covers the vast majority of real addresses.
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

// ─── Primitive validators ────────────────────────────────────────────────────

/**
 * Validates a single `name` value.
 * Rules: required, must be a string, 1–100 characters.
 * @param {*} name
 * @param {boolean} required - treat missing value as an error when true
 * @returns {string[]} error messages
 */
function validateName(name, required = true) {
  const errors = [];

  if (name === undefined || name === null || name === '') {
    if (required) errors.push('name is required');
    return errors;
  }

  if (typeof name !== 'string') {
    errors.push('name must be a string');
    return errors;
  }

  if (name.length < 1) {
    errors.push('name must be at least 1 character long');
  }
  if (name.length > 100) {
    errors.push('name must be no longer than 100 characters');
  }

  return errors;
}

/**
 * Validates a single `email` value.
 * Rules: required, must be a string, valid email format, max 254 characters.
 * @param {*} email
 * @param {boolean} required - treat missing value as an error when true
 * @returns {string[]} error messages
 */
function validateEmail(email, required = true) {
  const errors = [];

  if (email === undefined || email === null || email === '') {
    if (required) errors.push('email is required');
    return errors;
  }

  if (typeof email !== 'string') {
    errors.push('email must be a string');
    return errors;
  }

  if (email.length > 254) {
    errors.push('email must be no longer than 254 characters');
  }

  if (!EMAIL_REGEX.test(email)) {
    errors.push('email must be a valid email address (e.g. user@example.com)');
  }

  return errors;
}

/**
 * Validates a route/query parameter `id`.
 * Rules: required, must be a whole positive integer.
 * @param {*} id - typically a string from req.params or req.query
 * @returns {string[]} error messages
 */
function validateId(id) {
  const errors = [];

  if (id === undefined || id === null || id === '') {
    errors.push('id is required');
    return errors;
  }

  const parsed = Number(id);
  if (!Number.isFinite(parsed) || !Number.isInteger(parsed) || parsed <= 0) {
    errors.push('id must be a positive integer');
  }

  return errors;
}

// ─── Composite validators (one per endpoint shape) ───────────────────────────

/**
 * Validates the request body for POST /users (create).
 * Both `name` and `email` are required.
 *
 * @param {*} body - req.body
 * @returns {{ valid: boolean, errors: string[] }}
 */
function validateCreateUser(body) {
  if (!body || typeof body !== 'object' || Array.isArray(body)) {
    return { valid: false, errors: ['Request body must be a JSON object'] };
  }

  const errors = [
    ...validateName(body.name, true),
    ...validateEmail(body.email, true),
  ];

  return { valid: errors.length === 0, errors };
}

/**
 * Validates the request body for PUT /users/:id (full update).
 * Both `name` and `email` are required for a full replacement.
 *
 * @param {*} body - req.body
 * @returns {{ valid: boolean, errors: string[] }}
 */
function validateReplaceUser(body) {
  if (!body || typeof body !== 'object' || Array.isArray(body)) {
    return { valid: false, errors: ['Request body must be a JSON object'] };
  }

  const errors = [
    ...validateName(body.name, true),
    ...validateEmail(body.email, true),
  ];

  return { valid: errors.length === 0, errors };
}

/**
 * Validates the request body for PATCH /users/:id (partial update).
 * At least one of `name` or `email` must be supplied; any field that is
 * present is fully validated.
 *
 * @param {*} body - req.body
 * @returns {{ valid: boolean, errors: string[] }}
 */
function validatePatchUser(body) {
  if (!body || typeof body !== 'object' || Array.isArray(body)) {
    return { valid: false, errors: ['Request body must be a JSON object'] };
  }

  const hasName  = body.name  !== undefined;
  const hasEmail = body.email !== undefined;

  if (!hasName && !hasEmail) {
    return {
      valid: false,
      errors: ['Request body must include at least one field to update: name, email'],
    };
  }

  const errors = [
    ...(hasName  ? validateName(body.name,   true) : []),
    ...(hasEmail ? validateEmail(body.email, true) : []),
  ];

  return { valid: errors.length === 0, errors };
}

/**
 * Validates a single route/query parameter `id` and wraps the result.
 *
 * @param {*} id - typically req.params.id or req.query.id
 * @returns {{ valid: boolean, errors: string[] }}
 */
function validateParamId(id) {
  const errors = validateId(id);
  return { valid: errors.length === 0, errors };
}

module.exports = {
  // Primitive helpers (exported for unit-testing individual rules)
  validateName,
  validateEmail,
  validateId,
  // Composite validators (used directly in route handlers)
  validateCreateUser,
  validateReplaceUser,
  validatePatchUser,
  validateParamId,
};

