// Validation helper module
// Provides reusable field validators and a collectErrors runner for route handlers.

/**
 * Validates that a value is a finite integer (numeric id).
 * Accepts numbers and numeric strings (e.g. route params are always strings).
 *
 * @param {*} value
 * @returns {string|null} error message, or null if valid
 */
function validateId(value) {
  const num = Number(value);
  if (value === undefined || value === null || value === '') {
    return 'id is required';
  }
  if (!Number.isInteger(num) || num <= 0) {
    return 'id must be a positive integer';
  }
  return null;
}

/**
 * Validates a name field.
 *  - Required
 *  - Must be a string
 *  - Length 1–100 characters
 *
 * @param {*} value
 * @returns {string|null} error message, or null if valid
 */
function validateName(value) {
  if (value === undefined || value === null) {
    return 'name is required';
  }
  if (typeof value !== 'string') {
    return 'name must be a string';
  }
  const trimmed = value.trim();
  if (trimmed.length < 1) {
    return 'name must be at least 1 character';
  }
  if (trimmed.length > 100) {
    return 'name must be at most 100 characters';
  }
  return null;
}

/**
 * Validates an email field.
 *  - Required
 *  - Must be a string
 *  - Must match a standard email format
 *  - Maximum 254 characters (RFC 5321 limit)
 *
 * @param {*} value
 * @returns {string|null} error message, or null if valid
 */
function validateEmail(value) {
  if (value === undefined || value === null) {
    return 'email is required';
  }
  if (typeof value !== 'string') {
    return 'email must be a string';
  }
  if (value.length > 254) {
    return 'email must be at most 254 characters';
  }
  // RFC 5322-inspired pattern: local@domain.tld
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!emailRegex.test(value)) {
    return 'email must be a valid email address';
  }
  return null;
}

/**
 * Runs a map of named validator functions and collects all error messages.
 *
 * @param {Object.<string, function(): string|null>} checks
 *   Keys are field names (used only for ordering); values are zero-argument
 *   functions that return an error string or null.
 * @returns {string[]} Array of error messages (empty when all pass).
 *
 * @example
 *   const errors = collectErrors({
 *     id:    () => validateId(req.params.id),
 *     name:  () => validateName(req.body.name),
 *     email: () => validateEmail(req.body.email),
 *   });
 */
function collectErrors(checks) {
  const errors = [];
  for (const fn of Object.values(checks)) {
    const error = fn();
    if (error !== null) {
      errors.push(error);
    }
  }
  return errors;
}

module.exports = { validateId, validateName, validateEmail, collectErrors };

