/**
 * Validation helper module.
 *
 * Each validate* function returns an array of error strings.
 * An empty array means the input passed all checks.
 *
 * Usage:
 *   const errors = [...validateId(req.params.id), ...validateUserBody(req.body)];
 *   if (errors.length) return res.status(400).json({ errors });
 */

'use strict';

// ---------------------------------------------------------------------------
// Primitive validators
// ---------------------------------------------------------------------------

/**
 * Validate a route/query parameter that must be a positive integer id.
 * The raw value coming from Express params is always a string, so we coerce.
 *
 * @param {string|number} value - the raw param value
 * @param {string} [field='id'] - field name used in error messages
 * @returns {string[]} array of error messages (empty = valid)
 */
function validateId(value, field = 'id') {
  const errors = [];

  if (value === undefined || value === null || value === '') {
    errors.push(`"${field}" is required`);
    return errors; // further checks don't make sense if missing
  }

  const num = Number(value);
  if (!Number.isInteger(num) || num <= 0) {
    errors.push(`"${field}" must be a positive integer`);
  }

  return errors;
}

/**
 * Validate a name field.
 *
 * Rules:
 *  - required (non-empty after trimming)
 *  - must be a string
 *  - length between 1 and 100 characters (after trimming)
 *
 * @param {*} value - the raw value from req.body
 * @param {string} [field='name'] - field name used in error messages
 * @returns {string[]}
 */
function validateName(value, field = 'name') {
  const errors = [];

  if (value === undefined || value === null) {
    errors.push(`"${field}" is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`"${field}" must be a string`);
    return errors;
  }

  const trimmed = value.trim();

  if (trimmed.length === 0) {
    errors.push(`"${field}" must not be blank`);
  } else if (trimmed.length > 100) {
    errors.push(`"${field}" must be at most 100 characters (got ${trimmed.length})`);
  }

  return errors;
}

/**
 * Validate an email field.
 *
 * Rules:
 *  - required
 *  - must be a string
 *  - must match a basic RFC-5321-style pattern (local@domain.tld)
 *  - length at most 254 characters (RFC 5321 maximum)
 *
 * @param {*} value - the raw value from req.body
 * @param {string} [field='email'] - field name used in error messages
 * @returns {string[]}
 */
function validateEmail(value, field = 'email') {
  // Simple but practical email regex:
  //  - local part: printable chars excluding whitespace and @
  //  - @ separator
  //  - domain: labels separated by dots, each label 1–63 alnum/hyphen chars
  //  - TLD: at least 2 alpha chars
  const EMAIL_RE = /^[^\s@]+@[A-Za-z0-9]([A-Za-z0-9-]{0,61}[A-Za-z0-9])?(\.[A-Za-z0-9]([A-Za-z0-9-]{0,61}[A-Za-z0-9])?)*\.[A-Za-z]{2,}$/;

  const errors = [];

  if (value === undefined || value === null) {
    errors.push(`"${field}" is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`"${field}" must be a string`);
    return errors;
  }

  if (value.length === 0) {
