 * @param {string} field - Human-readable field name used in error messages.
 * @param {*} value
 * @returns {string[]} Errors found (0 or 1 entry).
 */
function validateRequired(field, value) {
  if (value === undefined || value === null || value === '') {
    return [`${field} is required`];
  }
  return [];
}

/**
 * Validate that a value is a finite number or a string that parses to one.
 * @param {string} field
 * @param {*} value
 * @returns {string[]}
 */
function validateNumeric(field, value) {
  if (value === undefined || value === null) return [];
  const num = Number(value);
  if (!Number.isFinite(num)) {
    return [`${field} must be a numeric value`];
  }
  return [];
}

/**
 * Validate that a value is a non-empty string (type check only — use
 * validateLength for length constraints).
 * @param {string} field
 * @param {*} value
 * @returns {string[]}
 */
function validateString(field, value) {
  if (value === undefined || value === null) return [];
  if (typeof value !== 'string') {
    return [`${field} must be a string`];
  }
  return [];
}

/**
 * Validate that a string's length falls within [min, max] (inclusive).
 * Skipped when the value is absent or fails a prior type check.
 * @param {string} field
 * @param {*} value
 * @param {number} min
 * @param {number} max
 * @returns {string[]}
 */
function validateLength(field, value, min, max) {
  if (value === undefined || value === null || typeof value !== 'string') return [];
  if (value.length < min || value.length > max) {
    return [`${field} must be between ${min} and ${max} characters`];
  }
  return [];
}

/**
 * Validate that a string matches a basic e-mail pattern and does not exceed
 * RFC 5321's 254-character maximum.
 * Skipped when the value is absent or fails a prior type check.
 * @param {string} field
 * @param {*} value
 * @returns {string[]}
 */
function validateEmail(field, value) {
  if (value === undefined || value === null || typeof value !== 'string') return [];
  const errors = [];
  if (!EMAIL_REGEX.test(value)) {
    errors.push(`${field} must be a valid email address`);
  }
  if (value.length > 254) {
    errors.push(`${field} must not exceed 254 characters`);
  }
  return errors;
}

