 * Validate a numeric URL/query parameter (always a string coming from Express).
 * Combines presence, numeric, and integer checks in one call.
 * @param {string} field
 * @param {*} value
 * @returns {string[]}
 */
function validateId(field, value) {
  const errors = [
    ...validateRequired(field, value),
  ];
  if (errors.length) return errors;           // skip further checks if absent
  errors.push(...validateNumeric(field, value));
  if (errors.length) return errors;
