 *                fields that are present are validated (PATCH-style PUT).
 * @returns {string[]}
 */
function validateUserBody(body, { requireAll = true } = {}) {
  const { name, email } = body;
  const errors = [];

  if (requireAll) {
    errors.push(...validateRequired('name', name));
    errors.push(...validateRequired('email', email));
  }

  // Type checks (run even when field is optional and present)
  errors.push(...validateString('name', name));
  errors.push(...validateString('email', email));

  // Constraint checks (only meaningful after type checks pass)
  const nameTypeOk = typeof name === 'string';
  const emailTypeOk = typeof email === 'string';

  if (nameTypeOk) {
    errors.push(...validateLength('name', name, 1, 100));
  }
  if (emailTypeOk) {
    errors.push(...validateEmail('email', email));
  }

  return errors;
