 *   { "errors": ["name is required", "email must be a valid email address"] }
 *
 * @param {() => string[]} validatorFn  Zero-argument function that returns errors.
 * @returns {import('express').RequestHandler}
 */
function validate(validatorFn) {
  return (req, res, next) => {
    const errors = validatorFn(req);
    if (errors.length > 0) {
      return res.status(400).json({ errors });
    }
    next();
  };
}

module.exports = {
  validate,
  validateRequired,
  validateNumeric,
  validateString,
  validateLength,
  validateEmail,
  validateId,
  validateUserBody,
};

