/**
 * Validation helper module.
 *
 * Each validator returns an array of error message strings.
 * An empty array means the value passed all checks.
 *
 * Higher-level helpers (validateUserId, validateUserBody) compose
 * the primitives and are imported directly by route handlers.
 */

'use strict';

// ---------------------------------------------------------------------------
// Primitive validators
// ---------------------------------------------------------------------------

/**
 * Validates that a route/query parameter is a whole-number id.
 *
 * @param {*}      value  - Raw value (typically req.params.id).
 * @param {string} field  - Field name used in error messages.
 * @returns {string[]}    - Array of validation error messages.
 */
function validateId(value, field = 'id') {
  const errors = [];

  if (value === undefined || value === null || value === '') {
    errors.push(`"${field}" is required`);
    return errors; // no point checking further
  }

  // Accept numeric strings from URL params as well as plain numbers
  if (!/^\d+$/.test(String(value))) {
    errors.push(`"${field}" must be a positive integer`);
    return errors;
  }

  const parsed = Number(value);
  if (!Number.isInteger(parsed) || parsed <= 0) {
    errors.push(`"${field}" must be a positive integer`);
  }

  return errors;
}

/**
 * Validates a "name" field.
 *
 * Rules:
 *   - Required (non-empty string)
 *   - Must be a string (not a number, array, object, …)
 *   - Length: 1–100 characters
 *
 * @param {*}      value  - Value from req.body.
 * @param {string} field  - Field name used in error messages.
 * @returns {string[]}
 */
function validateName(value, field = 'name') {
  const errors = [];

  if (value === undefined || value === null) {
    errors.push(`"${field}" is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`"${field}" must be a string`);
    return errors;
  }

  const trimmed = value.trim();

  if (trimmed.length === 0) {
    errors.push(`"${field}" must not be empty`);
  } else if (trimmed.length > 100) {
    errors.push(`"${field}" must be at most 100 characters`);
  }

  return errors;
}

/**
 * Validates an "email" field.
 *
 * Rules:
 *   - Required (non-empty string)
 *   - Must be a string
 *   - Must match a standard email pattern (local@domain.tld)
 *   - Length: max 254 characters (RFC 5321 §4.5.3.1)
 *
 * @param {*}      value  - Value from req.body.
 * @param {string} field  - Field name used in error messages.
 * @returns {string[]}
 */
function validateEmail(value, field = 'email') {
  // RFC-5322-inspired pattern; strict enough for API validation without
  // rejecting common valid addresses.
  const EMAIL_RE =
    /^[a-zA-Z0-9.!#$%&'*+/=?^_`{|}~-]+@[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(?:\.[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)+$/;

  const errors = [];

  if (value === undefined || value === null) {
    errors.push(`"${field}" is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`"${field}" must be a string`);
    return errors;
  }

  if (value.trim().length === 0) {
    errors.push(`"${field}" must not be empty`);
    return errors;
  }

  if (value.length > 254) {
    errors.push(`"${field}" must be at most 254 characters`);
  }

  if (!EMAIL_RE.test(value)) {
    errors.push(`"${field}" must be a valid email address`);
  }

  return errors;
}

// ---------------------------------------------------------------------------
// Composite validators used by route handlers
// ---------------------------------------------------------------------------

/**
 * Validates a URL/route :id parameter.
 *
 * Returns { valid, errors } where `errors` is an array of message strings.
 *
 * @param {*} id - Value of req.params.id.
 * @returns {{ valid: boolean, errors: string[] }}
 */
function validateUserId(id) {
  const errors = validateId(id, 'id');
  return { valid: errors.length === 0, errors };
}

/**
 * Validates the JSON body for user create / update operations.
 *
 * @param {object}  body        - req.body
 * @param {object}  [options]
 * @param {boolean} [options.requireName=true]   - Treat missing name as error.
 * @param {boolean} [options.requireEmail=true]  - Treat missing email as error.
 *
 * When requireName/requireEmail are false (PATCH-style partial updates),
 * the field is only validated if it is present in the body.
 *
 * @returns {{ valid: boolean, errors: string[] }}
 */
function validateUserBody(body, { requireName = true, requireEmail = true } = {}) {
  const errors = [];

  const namePresent = body !== undefined && body !== null && 'name' in body;
  const emailPresent = body !== undefined && body !== null && 'email' in body;

  if (requireName || namePresent) {
    if (!namePresent && requireName) {
      errors.push('"name" is required');
    } else if (namePresent) {
      errors.push(...validateName(body.name, 'name'));
    }
  }

  if (requireEmail || emailPresent) {
    if (!emailPresent && requireEmail) {
      errors.push('"email" is required');
    } else if (emailPresent) {
      errors.push(...validateEmail(body.email, 'email'));
    }
  }

  return { valid: errors.length === 0, errors };
}

/**
 * Express middleware factory that sends a 400 response when the caller
 * supplies an invalid :id parameter.  Attach to individual routes:
 *
 *   router.get('/:id', requireValidId(), handler)
 */
function requireValidId() {
  return function (req, res, next) {
    const { valid, errors } = validateUserId(req.params.id);
    if (!valid) {
      return res.status(400).json({ errors });
    }
    next();
  };
}

module.exports = {
  // Primitives (useful for custom compositions)
  validateId,
  validateName,
  validateEmail,
  // Composite helpers
  validateUserId,
  validateUserBody,
  // Middleware
  requireValidId,
};

