  }

  if (hasName) errors.push(...validateName(body.name, 'name'));
  if (hasEmail) errors.push(...validateEmail(body.email, 'email'));

  if (errors.length) {
    res.status(400).json({ errors });
    return false;
  }
  return true;
}

