// GET /users/:id  — fetch a single user
//   Validates: id is a positive integer
// ---------------------------------------------------------------------------
app.get('/users/:id', (req, res) => {
  const id = validateParamId(req, res);
  if (id === null) return;

  const user = users.find(u => u.id === id);
  if (!user) return res.status(404).json({ errors: [`user with id ${id} not found`] });

  res.json(user);
});

